#ifndef RMSNORM_H128_KERNEL_H_
#define RMSNORM_H128_KERNEL_H_

#include <cstdint>
#include <cuda_runtime.h>
#include <cuda_bf16.h>

#ifdef __cplusplus
extern "C" {
#endif

// RMSNorm for hidden_size=128, bf16 input/weight/output.
// hidden_states: [batch_size, 128]
// weight: [128]
// output: [batch_size, 128]
void rmsnorm_h128_launch(const __nv_bfloat16* hidden_states,
                         const __nv_bfloat16* weight,
                         __nv_bfloat16* output,
                         int64_t batch_size,
                         cudaStream_t stream);

#ifdef __cplusplus
}
#endif

#endif  // RMSNORM_H128_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>

#if defined(__CUDA_ARCH__) && (__CUDA_ARCH__ >= 800)
#define USE_LDG 1
#else
#define USE_LDG 0
#endif

// --------- helpers ---------
__device__ __forceinline__ float warp_sum(float v) {
#pragma unroll
  for (int offset = 16; offset > 0; offset >>= 1) {
    v += __shfl_down_sync(0xffffffff, v, offset);
  }
  return v;
}

template <int BLOCK_THREADS>
__device__ __forceinline__ float block_sum(float v) {
  static_assert(BLOCK_THREADS == 64 || BLOCK_THREADS == 128,
                "block_sum only supports 64 or 128 threads");
  constexpr int WARPS = BLOCK_THREADS / 32;

  __shared__ float smem[WARPS];
  const int lane = threadIdx.x & 31;
  const int warp = threadIdx.x >> 5;

  v = warp_sum(v);
  if (lane == 0) smem[warp] = v;
  __syncthreads();

  float out = 0.0f;
  if (warp == 0) {
    out = (lane < WARPS) ? smem[lane] : 0.0f;
    out = warp_sum(out);
  }

  __shared__ float block_out;
  if (threadIdx.x == 0) block_out = out;
  __syncthreads();
  return block_out;
}

__device__ __forceinline__ __nv_bfloat162 load_bf162(const __nv_bfloat16* p) {
#if USE_LDG
  // Read-only cache path on Ampere+ when possible
  return __ldg(reinterpret_cast<const __nv_bfloat162*>(p));
#else
  return *reinterpret_cast<const __nv_bfloat162*>(p);
#endif
}

// --------- kernels ---------
// Vectorized kernel: 64 threads, each handles 2 elems => 128 elems/row
template <int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS, 8)
void rmsnorm_h128_vec2(const __nv_bfloat16* __restrict__ hidden_states,
                       const __nv_bfloat16* __restrict__ weight,
                       __nv_bfloat16* __restrict__ output,
                       int64_t batch_size) {
  constexpr int H = 128;
  constexpr float INV_H = 1.0f / 128.0f;
  constexpr float EPS = 1.0e-6f;

  const int64_t row = (int64_t)blockIdx.x;
  if (row >= batch_size) return;

  const int t = (int)threadIdx.x; // 0..63
  const int col0 = t * 2;
  const int64_t base = row * (int64_t)H + (int64_t)col0;

  const __nv_bfloat162 x2b = load_bf162(hidden_states + base);
  const float2 x2 = __bfloat1622float2(x2b);

  const float ss = fmaf(x2.x, x2.x, x2.y * x2.y);
  const float sumsq = block_sum<BLOCK_THREADS>(ss);

  __shared__ float inv_rms_s;
  if (threadIdx.x == 0) {
    inv_rms_s = rsqrtf(fmaf(sumsq, INV_H, EPS));
  }
  __syncthreads();

  const __nv_bfloat162 w2b = load_bf162(weight + col0);
  const float2 w2 = __bfloat1622float2(w2b);

  const float y0 = (x2.x * inv_rms_s) * w2.x;
  const float y1 = (x2.y * inv_rms_s) * w2.y;

  *reinterpret_cast<__nv_bfloat162*>(output + base) = __floats2bfloat162_rn(y0, y1);
}

// Scalar fallback: 128 threads, each handles 1 elem => safe for any alignment
template <int BLOCK_THREADS>
__global__ __launch_bounds__(BLOCK_THREADS, 4)
void rmsnorm_h128_scalar(const __nv_bfloat16* __restrict__ hidden_states,
                         const __nv_bfloat16* __restrict__ weight,
                         __nv_bfloat16* __restrict__ output,
                         int64_t batch_size) {
  constexpr int H = 128;
  constexpr float INV_H = 1.0f / 128.0f;
  constexpr float EPS = 1.0e-6f;

  const int64_t row = (int64_t)blockIdx.x;
  if (row >= batch_size) return;

  const int col = (int)threadIdx.x; // 0..127
  const int64_t idx = row * (int64_t)H + (int64_t)col;

  const float x = __bfloat162float(hidden_states[idx]);
  const float sumsq = block_sum<BLOCK_THREADS>(x * x);

  __shared__ float inv_rms_s;
  if (threadIdx.x == 0) {
    inv_rms_s = rsqrtf(fmaf(sumsq, INV_H, EPS));
  }
  __syncthreads();

  const float w = __bfloat162float(weight[col]);
  output[idx] = __float2bfloat16_rn((x * inv_rms_s) * w);
}

void rmsnorm_h128_launch(const __nv_bfloat16* hidden_states,
                         const __nv_bfloat16* weight,
                         __nv_bfloat16* output,
                         int64_t batch_size,
                         cudaStream_t stream) {
  if (batch_size <= 0) return;

  // NOTE: vec2 requires 4B alignment for all three pointers
  const uintptr_t x_addr = reinterpret_cast<uintptr_t>(hidden_states);
  const uintptr_t w_addr = reinterpret_cast<uintptr_t>(weight);
  const uintptr_t o_addr = reinterpret_cast<uintptr_t>(output);
  const bool aligned4 = ((x_addr | w_addr | o_addr) & 0x3u) == 0u;

  dim3 grid((unsigned int)batch_size, 1, 1);

  if (aligned4) {
    constexpr int THREADS = 64;
    dim3 block(THREADS, 1, 1);
    rmsnorm_h128_vec2<THREADS><<<grid, block, 0, stream>>>(hidden_states, weight, output, batch_size);
  } else {
    constexpr int THREADS = 128;
    dim3 block(THREADS, 1, 1);
    rmsnorm_h128_scalar<THREADS><<<grid, block, 0, stream>>>(hidden_states, weight, output, batch_size);
  }
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>

#include <sstream>
#include <stdexcept>

#include "kernel.h"

static inline void cuda_check(cudaError_t err, const char* ctx) {
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << ctx << ": CUDA error: " << cudaGetErrorString(err);
    throw std::runtime_error(oss.str());
  }
}

static inline void validate_inputs(const torch::Tensor& hidden_states, const torch::Tensor& weight) {
  if (!hidden_states.defined() || !weight.defined()) {
    throw std::runtime_error("run: hidden_states and weight must be defined tensors");
  }
  if (hidden_states.dim() != 2) {
    throw std::runtime_error("run: hidden_states must be 2D [batch_size, 128]");
  }
  if (weight.dim() != 1) {
    throw std::runtime_error("run: weight must be 1D [128]");
  }
  if (hidden_states.size(1) != 128) {
    std::ostringstream oss;
    oss << "run: hidden_states.size(1) must be 128, got " << hidden_states.size(1);
    throw std::runtime_error(oss.str());
  }
  if (weight.size(0) != 128) {
    std::ostringstream oss;
    oss << "run: weight.size(0) must be 128, got " << weight.size(0);
    throw std::runtime_error(oss.str());
  }
  if (hidden_states.dtype() != torch::kBFloat16) {
    throw std::runtime_error("run: hidden_states must be torch.bfloat16");
  }
  if (weight.dtype() != torch::kBFloat16) {
    throw std::runtime_error("run: weight must be torch.bfloat16");
  }
  if (hidden_states.numel() == 0) {
    throw std::runtime_error("run: hidden_states must be non-empty");
  }
}

static inline torch::Tensor run_impl(torch::Tensor hidden_states, torch::Tensor weight) {
  validate_inputs(hidden_states, weight);

  // Move to CUDA if needed.
  if (!hidden_states.device().is_cuda()) hidden_states = hidden_states.to(torch::kCUDA);
  if (!weight.device().is_cuda()) weight = weight.to(torch::kCUDA);

  if (!hidden_states.device().is_cuda() || !weight.device().is_cuda()) {
    throw std::runtime_error("run: failed to move inputs to CUDA");
  }

  // Ensure contiguous (required by kernel indexing/coalescing).
  auto x = hidden_states.contiguous();
  auto w = weight.contiguous();
  auto out = torch::empty_like(x);

  const int64_t batch_size = x.size(0);

  // Use PyTorch current CUDA stream (NOT default stream).
  cudaStream_t stream = at::cuda::getDefaultCUDAStream();

  const __nv_bfloat16* x_ptr =
      reinterpret_cast<const __nv_bfloat16*>(x.data_ptr<at::BFloat16>());
  const __nv_bfloat16* w_ptr =
      reinterpret_cast<const __nv_bfloat16*>(w.data_ptr<at::BFloat16>());
  __nv_bfloat16* o_ptr =
      reinterpret_cast<__nv_bfloat16*>(out.data_ptr<at::BFloat16>());

  rmsnorm_h128_launch(x_ptr, w_ptr, o_ptr, batch_size, stream);

  cuda_check(cudaGetLastError(), "rmsnorm_h128_launch (kernel launch)");
  // Do not synchronize here in real workloads; but keep for correctness/debug in this harness.
  cuda_check(cudaStreamSynchronize(stream), "rmsnorm_h128_launch (stream sync)");

  return out;
}

torch::Tensor run(pybind11::args args, pybind11::kwargs kwargs) {
  torch::Tensor hidden_states;
  torch::Tensor weight;

  if (args.size() >= 2) {
    hidden_states = args[0].cast<torch::Tensor>();
    weight = args[1].cast<torch::Tensor>();
  } else {
    if (!kwargs || !kwargs.contains("hidden_states") || !kwargs.contains("weight")) {
      throw std::runtime_error("run: expected (hidden_states, weight) as positional args or kwargs");
    }
    hidden_states = kwargs["hidden_states"].cast<torch::Tensor>();
    weight = kwargs["weight"].cast<torch::Tensor>();
  }

  return run_impl(hidden_states, weight);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "Kernel execution function (rmsnorm_h128)");
}
